+    if !ptr.is_null() {
+        // ptr is the address of glibc's _IO_list_all variable (a FILE*).
+        // Set it to NULL to prevent glibc's exit handler from iterating.
+        let glibc_list_ptr = ptr as *mut *mut c_void;
+        unsafe { *glibc_list_ptr = ptr::null_mut() };
+    }
